const input = $input.first().json;
const body = input.body || input;

return [{
  json: {
    type: body.type || 'unknown',
    project: body.project || 'unknown',
    phase: body.phase || '',
    plan: body.plan || '',
    summary: body.summary || 'Input required',
    details: body.details || '',
    action_needed: body.action_needed || 'Please respond',
    session_url: body.session_url || '',
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;
const typeEmoji = {'checkpoint': ':pause_button:', 'decision': ':thinking_face:', 'blocked': ':octagonal_sign:', 'verification': ':white_check_mark:', 'test': ':test_tube:', 'unknown': ':bell:'};
const emoji = typeEmoji[data.type] || ':bell:';

let location = '';
if (data.phase && data.plan) location = '*Phase:* ' + data.phase + ' | *Plan:* ' + data.plan;
else if (data.phase) location = '*Phase:* ' + data.phase;
else if (data.plan) location = '*Plan:* ' + data.plan;

const blocks = [
  {type: 'header', text: {type: 'plain_text', text: emoji + ' GSD Input Required', emoji: true}},
  {type: 'section', fields: [{type: 'mrkdwn', text: '*Project:*\n' + data.project}, {type: 'mrkdwn', text: '*Type:*\n' + data.type}]}
];

if (location) blocks.push({type: 'section', text: {type: 'mrkdwn', text: location}});
blocks.push({type: 'section', text: {type: 'mrkdwn', text: '*Summary:*\n' + data.summary}});
if (data.details && data.details.trim()) blocks.push({type: 'section', text: {type: 'mrkdwn', text: '*Details:*\n' + data.details}});
blocks.push({type: 'section', text: {type: 'mrkdwn', text: '*Action needed:*\n' + data.action_needed}});
if (data.session_url && data.session_url.trim()) blocks.push({type: 'actions', elements: [{type: 'button', text: {type: 'plain_text', text: 'Open Claude Session', emoji: true}, url: data.session_url, action_id: 'open_session'}]});
blocks.push({type: 'divider'}, {type: 'context', elements: [{type: 'mrkdwn', text: 'Received at ' + data.timestamp}]});

return [{json: {...data, slack_blocks: blocks, slack_text: 'GSD Input Required: ' + data.project + ' - ' + data.summary}}];
